/**
 * Solver Types - Communication between TypeScript and Python solver
 *
 * These types define the contract for the solver adapter.
 * The Python solver uses snake_case internally, but the adapter
 * handles conversion to/from camelCase for TypeScript consumers.
 */

import type { MaintenanceType, ResourceConstraints } from "./maintenance";
import type { Asset } from "./asset";

/**
 * Input to the optimization solver
 */
export interface SolverInput {
  events: SolverEvent[];
  assets: Asset[];
  maintenanceTypes: MaintenanceType[];
  constraints: ResourceConstraints;
  planningHorizonWeeks: number;
  objective?: SolverObjective;
  settings?: SolverSettings;
}

export interface SolverEvent {
  id: string;
  assetId: string;
  maintenanceTypeId: string;
  manHours: number;
  earliestPeriod: number;
  latestPeriod: number;
  targetPeriod: number;
  priority: number; // 1-10
}

export interface SolverObjective {
  peakWorkloadWeight?: number; // Default: 1.0
  levelingWeight?: number; // Default: 0.5
  complianceWeight?: number; // Default: 0.3
}

export interface SolverSettings {
  timeoutSeconds?: number; // Default: 60
  gapTolerance?: number; // MIP gap (0.01 = 1%), default: 0.01
}

/**
 * Output from the optimization solver
 */
export interface SolverOutput {
  status: SolverStatus;
  solution: SolverSolution | null;
  metrics: SolverMetrics | null;
  diagnostics: SolverDiagnostics;
}

export type SolverStatus =
  | "OPTIMAL"
  | "FEASIBLE"
  | "INFEASIBLE"
  | "TIMEOUT"
  | "ERROR";

export interface SolverSolution {
  assignments: EventAssignment[];
  workloadProfile: PeriodWorkload[];
}

export interface EventAssignment {
  eventId: string;
  assignedPeriod: number;
  deviation: number; // From target (assigned - target)
}

export interface PeriodWorkload {
  period: number;
  manHours: number;
  eventCount: number;
  utilization: number; // 0-1
}

export interface SolverMetrics {
  objectiveValue: number;
  peakWorkload: number;
  averageWorkload: number;
  workloadVariance: number;
  workloadCv: number; // Coefficient of variation
  complianceRate: number; // 0-1
  totalCost: number;
}

export interface SolverDiagnostics {
  solverName: string;
  solveTimeMs: number;
  iterations: number;
  mipGap?: number;
  nodeCount?: number;
  warnings?: string[];
}

/**
 * Solver job for async execution
 */
export interface SolverJob {
  id: string;
  input: SolverInput;
  status: SolverJobStatus;
  progress: number; // 0-100
  output?: SolverOutput;
  error?: string;
  createdAt: string;
  startedAt?: string;
  completedAt?: string;
}

export type SolverJobStatus =
  | "PENDING"
  | "RUNNING"
  | "COMPLETED"
  | "FAILED"
  | "CANCELLED";

